import * as THREE from "three";
import { OrbitControls } from "three/addons/controls/OrbitControls.js";
import { RoomEnvironment } from "three/addons/environments/RoomEnvironment.js";
import { generatePlanetTextures, createElevationSampler } from "./planet.js";
import { makeAtmosphere } from "./atmosphere.js";
import { makeRing } from "./ring.js";

const PLANET_RADIUS = 2;
const PLANET_SEED = 42;

// Bird's-eye view: orbit the planet and click a marked island to land on it.
export function createPlanetView(renderer, { onIslandClick } = {}) {
  const canvas = renderer.domElement;

  const scene = new THREE.Scene();
  scene.background = new THREE.Color(0x07050f); // soft deep-violet void

  // Image-based lighting so the gold islands have something to reflect.
  const pmrem = new THREE.PMREMGenerator(renderer);
  scene.environment = pmrem.fromScene(new RoomEnvironment(), 0.04).texture;

  const camera = new THREE.PerspectiveCamera(
    45, window.innerWidth / window.innerHeight, 0.1, 1000
  );
  camera.position.set(0, 1.4, 6.5);

  const controls = new OrbitControls(camera, canvas);
  controls.enableDamping = true;
  controls.dampingFactor = 0.06;
  controls.enablePan = false;
  controls.minDistance = 3.0;
  controls.maxDistance = 9.0;
  controls.rotateSpeed = 0.5;
  controls.autoRotate = false;

  // ---------- lighting ----------
  const sun = new THREE.DirectionalLight(0xfff4e8, 1.8);
  sun.position.set(5, 2.5, 4);
  scene.add(sun);
  scene.add(new THREE.AmbientLight(0x6a5a92, 0.25));
  const rim = new THREE.DirectionalLight(0x8a7ab8, 0.6);
  rim.position.set(-5, -1, -4);
  scene.add(rim);

  // ---------- starfield ----------
  scene.add(makeStars());

  // ---------- planet ----------
  const planetGroup = new THREE.Group();
  scene.add(planetGroup);
  planetGroup.rotation.z = 0.42; // Saturn-like axial tilt so the ring reads

  const { colorMap, bumpMap, roughnessMap, metalnessMap, cloudMap } =
    generatePlanetTextures({ seed: PLANET_SEED });

  const planet = new THREE.Mesh(
    new THREE.SphereGeometry(PLANET_RADIUS, 128, 128),
    new THREE.MeshStandardMaterial({
      map: colorMap,
      bumpMap,
      bumpScale: 0.015,
      roughnessMap,
      roughness: 1.0,
      metalnessMap,
      metalness: 1.0,
      envMapIntensity: 0.3,
    })
  );
  planetGroup.add(planet);

  const clouds = new THREE.Mesh(
    new THREE.SphereGeometry(PLANET_RADIUS * 1.012, 96, 96),
    new THREE.MeshStandardMaterial({
      map: cloudMap, transparent: true, depthWrite: false,
      color: 0xf2ecff, opacity: 0.4, roughness: 1.0,
    })
  );
  planetGroup.add(clouds);

  planetGroup.add(makeAtmosphere(PLANET_RADIUS * 1.09, {
    color: new THREE.Color(0xc9a6ff), power: 2.2, intensity: 0.9,
  }));

  planetGroup.add(makeRing(PLANET_RADIUS));

  // ---------- the landable island hotspot ----------
  // Find a guaranteed patch of gold land (highest elevation), then place the
  // marker exactly on the texel that paints it (geometry UV convention).
  const sampler = createElevationSampler({ seed: PLANET_SEED });
  const spot = sampler.findLandSpots({ latLimit: 55, step: 3 })[0]
    || { lat: 20, lon: 40 };
  const hotspot = makeHotspot(spot.lat, spot.lon, PLANET_RADIUS);
  planet.add(hotspot.group); // rides the planet so it rotates in sync

  // ---------- interaction (only while this view is active) ----------
  const raycaster = new THREE.Raycaster();
  const pointer = new THREE.Vector2();
  let hovered = false;
  let pointerDownAt = null;
  let active = false;

  function pickHit(event) {
    pointer.x = (event.clientX / window.innerWidth) * 2 - 1;
    pointer.y = -(event.clientY / window.innerHeight) * 2 + 1;
    raycaster.setFromCamera(pointer, camera);
    return raycaster.intersectObject(hotspot.group, true).length > 0;
  }

  function onPointerMove(e) {
    const hit = pickHit(e);
    if (hit !== hovered) {
      hovered = hit;
      canvas.style.cursor = hit ? "pointer" : "default";
    }
  }
  function onPointerDown(e) { pointerDownAt = { x: e.clientX, y: e.clientY }; }
  function onPointerUp(e) {
    if (!pointerDownAt) return;
    const moved = Math.hypot(e.clientX - pointerDownAt.x, e.clientY - pointerDownAt.y);
    pointerDownAt = null;
    if (moved > 6) return; // was an orbit drag
    if (pickHit(e)) onIslandClick?.();
  }

  function update(dt, t) {
    planet.rotation.y += dt * 0.03;
    clouds.rotation.y += dt * 0.04;
    // Pulse the hotspot; lift/enlarge on hover.
    const base = 1 + Math.sin(t * 2) * 0.08;
    const target = hovered ? 1.6 : base;
    hotspot.ring.scale.setScalar(
      THREE.MathUtils.lerp(hotspot.ring.scale.x || 1, target, 0.15)
    );
    hotspot.ring.material.opacity = hovered ? 1.0 : 0.85;
    hotspot.beam.material.opacity = 0.35 + Math.sin(t * 3) * 0.12;
    controls.update();
  }

  function enter() {
    active = true;
    canvas.addEventListener("pointermove", onPointerMove);
    canvas.addEventListener("pointerdown", onPointerDown);
    canvas.addEventListener("pointerup", onPointerUp);
  }
  function exit() {
    active = false;
    hovered = false;
    canvas.style.cursor = "default";
    canvas.removeEventListener("pointermove", onPointerMove);
    canvas.removeEventListener("pointerdown", onPointerDown);
    canvas.removeEventListener("pointerup", onPointerUp);
  }
  function resize() {
    camera.aspect = window.innerWidth / window.innerHeight;
    camera.updateProjectionMatrix();
  }

  return { scene, camera, update, enter, exit, resize };
}

// ---- helpers ----

function makeStars() {
  const count = 2400;
  const positions = new Float32Array(count * 3);
  const colors = new Float32Array(count * 3);
  const tint = new THREE.Color();
  for (let i = 0; i < count; i++) {
    const r = 200 + Math.random() * 200;
    const u = Math.random() * 2 - 1;
    const a = Math.random() * Math.PI * 2;
    const s = Math.sqrt(1 - u * u);
    positions[i * 3] = r * s * Math.cos(a);
    positions[i * 3 + 1] = r * u;
    positions[i * 3 + 2] = r * s * Math.sin(a);
    const warm = Math.random();
    tint.setHSL(0.62 + warm * 0.18, 0.35, 0.62 + Math.random() * 0.3);
    colors[i * 3] = tint.r; colors[i * 3 + 1] = tint.g; colors[i * 3 + 2] = tint.b;
  }
  const geo = new THREE.BufferGeometry();
  geo.setAttribute("position", new THREE.BufferAttribute(positions, 3));
  geo.setAttribute("color", new THREE.BufferAttribute(colors, 3));
  const mat = new THREE.PointsMaterial({
    size: 1.1, sizeAttenuation: true, vertexColors: true,
    transparent: true, opacity: 0.9, depthWrite: false,
  });
  return new THREE.Points(geo, mat);
}

// Convert a texture (lat, lon) to the matching point on the SphereGeometry,
// using three's UV → vertex convention so the marker sits on the painted land.
function latLonToSurface(latDeg, lonDeg, radius) {
  const u = (lonDeg + 180) / 360;
  const v = (90 - latDeg) / 180;
  const theta = u * Math.PI * 2;
  const phi = v * Math.PI;
  return new THREE.Vector3(
    -radius * Math.cos(theta) * Math.sin(phi),
    radius * Math.cos(phi),
    radius * Math.sin(theta) * Math.sin(phi)
  );
}

// A pulsing ring flat on the surface plus an outward beam — the "land here"
// marker. Returned parts are animated by the view's update loop.
function makeHotspot(latDeg, lonDeg, radius) {
  const pos = latLonToSurface(latDeg, lonDeg, radius);
  const group = new THREE.Group();
  group.position.copy(pos);
  // Local +Y points away from the planet centre.
  group.quaternion.setFromUnitVectors(
    new THREE.Vector3(0, 1, 0), pos.clone().normalize()
  );

  const ring = new THREE.Mesh(
    new THREE.TorusGeometry(0.16, 0.022, 14, 40),
    new THREE.MeshBasicMaterial({
      color: 0xffd27a, transparent: true, opacity: 0.85,
      blending: THREE.AdditiveBlending, depthWrite: false,
    })
  );
  ring.rotation.x = -Math.PI / 2; // lie flat on the surface
  ring.position.y = 0.01;

  const beam = new THREE.Mesh(
    new THREE.CylinderGeometry(0.05, 0.12, 0.5, 16, 1, true),
    new THREE.MeshBasicMaterial({
      color: 0xffd27a, transparent: true, opacity: 0.4,
      blending: THREE.AdditiveBlending, depthWrite: false, side: THREE.DoubleSide,
    })
  );
  beam.position.y = 0.25;

  group.add(ring, beam);
  return { group, ring, beam };
}

